mapper.select:
SELECT COALESCE(FLOOR(SUM(total_study_second) / 60), 0)
FROM edu_study_record
WHERE student_id = #{studentId}

SELECT COUNT(DISTINCT DATE(update_time))
FROM edu_study_record
WHERE student_id = #{studentId}

SELECT COALESCE(SUM(total_study_second), 0)
FROM edu_study_record
WHERE student_id = #{studentId} AND DATE(update_time) = #{date}

mapper.delete:
DELETE FROM edu_growth_week_plan
WHERE student_id = #{studentId}
  AND week_start_date = #{weekStartDate}

DELETE t
FROM edu_growth_plan_task t
INNER JOIN edu_growth_week_plan p ON p.id = t.plan_id
WHERE p.student_id = #{studentId}
  AND p.week_start_date = #{weekStartDate}

mapper.update:
UPDATE edu_growth_plan_task
SET completed = CASE WHEN #{completed} THEN 1 ELSE 0 END,
    complete_time = CASE WHEN #{completed} THEN NOW() ELSE NULL END,
    update_time = NOW()
WHERE id = #{taskId}
  AND student_id = #{studentId}

mapper.select:
SELECT qkp.knowledge_point_id AS knowledgePointId, q.question_type AS questionType, COUNT(pr.id) AS practiceCount, SUM(CASE WHEN pr.is_correct = 1 THEN 1 ELSE 0 END) AS correctCount, ROUND(SUM(CASE WHEN pr.is_correct = 1 THEN 1 ELSE 0 END) * 100 / COUNT(pr.id)) AS mastery FROM edu_practice_record pr INNER JOIN edu_question q ON q.id = pr.question_id AND q.deleted = 0 AND q.status = 1 INNER JOIN edu_question_knowledge_point qkp ON qkp.question_id = pr.question_id WHERE pr.user_id = #{studentId} AND pr.deleted = 0 AND qkp.knowledge_point_id IN
#{id}
GROUP BY qkp.knowledge_point_id, q.question_type ORDER BY qkp.knowledge_point_id ASC, q.question_type ASC
